  INDIGO: "#4338CA",
  VIOLET: "#8A3FFC",
  PINK: "#FF94DB",
  FUCHSIA: "#EB3FA9",
  MAGENTA: "#C2185B",
  PETRUS_RED: "#8B0000",
  CARMINE: "#D4433A",
  PUMPKIN: "#D6702A",
